        const SPADES = `<path d="M 45 22 L 45 35 Q 45 45 35 45 L 22 45 L 22 55 L 35 55 Q 45 55 45 65 L 45 78 L 55 78 L 55 65 Q 55 55 65 55 L 78 55 L 78 45 L 65 45 Q 55 45 55 35 L 55 22 Z"/><circle cx="50" cy="14" r="12"/><circle cx="39" cy="23" r="9"/><circle cx="61" cy="23" r="9"/><circle cx="50" cy="86" r="12"/><circle cx="39" cy="77" r="9"/><circle cx="61" cy="77" r="9"/><circle cx="14" cy="50" r="12"/><circle cx="23" cy="39" r="9"/><circle cx="23" cy="61" r="9"/><circle cx="86" cy="50" r="12"/><circle cx="77" cy="39" r="9"/><circle cx="77" cy="61" r="9"/>`;
        const WILDCARD = `<path d="M 50 12 L 61 31 L 83 31 L 72 50 L 83 69 L 61 69 L 50 88 L 39 69 L 17 69 L 28 50 L 17 31 L 39 31 Z" /><circle cx="50" cy="12" r="6"/><circle cx="83" cy="31" r="6"/><circle cx="83" cy="69" r="6"/><circle cx="50" cy="88" r="6"/><circle cx="17" cy="69" r="6"/><circle cx="17" cy="31" r="6"/>`;
        const EAGLE = `<path d="M50 20 C60 10, 80 15, 90 30 C80 35, 60 30, 50 40 C40 30, 20 35, 10 30 C20 15, 40 10, 50 20 Z M45 40 L55 40 L50 60 Z M30 50 L45 45 L50 60 Z M70 50 L55 45 L50 60 Z" fill="${GOLD}"/>`;

