        const drawSide = () => {
            const svg = `
            <svg xmlns="http://www.w3.org/2000/svg" width="320" height="1400" viewBox="0 0 320 1400">
                <rect x="0" y="0" width="320" height="700" fill="${RED}"/>
                <rect x="0" y="700" width="320" height="700" fill="${BLUE}"/>
                <g transform="translate(160, 233) translate(-50, -50)">${drawSymbol(HEARTS, GOLD)}</g>
                <g transform="translate(160, 467) translate(-50, -50)">${drawSymbol(DIAMONDS, GOLD)}</g>
                <g transform="translate(160, 700) scale(1.5) translate(-50, -50)">${drawSymbol(WILDCARD, GOLD)}</g>
                <g transform="translate(160, 933) translate(-50, -50)">${drawSymbol(CLUBS, GOLD)}</g>
                <g transform="translate(160, 1167) translate(-50, -50)">${drawSymbol(SPADES, GOLD)}</g>
            </svg>`;
            return svgToDataUri(svg);
        };



        
        const createSALogoTexture = (bgColor) => {
            const canvas = document.createElement('canvas');
            canvas.width = 1024;
            canvas.height = 320;
            const ctx = canvas.getContext('2d');
            
            ctx.fillStyle = bgColor;
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            
            const tex = new THREE.CanvasTexture(canvas);
            const img = new Image();
            img.src = "data:image/png;base64,";
            img.onload = () => {
                const targetH = 150; // Made smaller as requested
                const aspect = img.width / img.height;
                const targetW = targetH * aspect;
                ctx.drawImage(img, (1000 - targetW) / 2, (320 - targetH) / 2, targetW, targetH);
                tex.needsUpdate = true;
            };
            
            return tex;
        };
        const drawSealSymbol = () => {
            const canvas = document.createElement("canvas");
            canvas.width = 512;
            canvas.height = 512;
            const ctx = canvas.getContext("2d");

            // Black circular background
            ctx.fillStyle = "#000000";
            ctx.beginPath();
            ctx.arc(256, 256, 250, 0, Math.PI * 2);
            ctx.fill();

            // 4 Interlocking white circles (clover arrangement)
            ctx.strokeStyle = "#ffffff";
            ctx.lineWidth = 20;
            const radius = 90;
            const offset = 65;

            // Top
            ctx.beginPath();
            ctx.arc(256, 256 - offset, radius, 0, Math.PI * 2);
            ctx.stroke();
            // Bottom
            ctx.beginPath();
            ctx.arc(256, 256 + offset, radius, 0, Math.PI * 2);
            ctx.stroke();
            // Left
            ctx.beginPath();
            ctx.arc(256 - offset, 256, radius, 0, Math.PI * 2);
            ctx.stroke();
            // Right
            ctx.beginPath();
            ctx.arc(256 + offset, 256, radius, 0, Math.PI * 2);
            ctx.stroke();

            return canvas.toDataURL();
        }

        function init() {
            const container = document.getElementById('canvas-container');
            const scene = new THREE.Scene();


            scene.background = new THREE.Color(0xfcf5e3); // Pale yellow wall color

            const roomGroup = new THREE.Group();

            // 1. Floor
            const floorGeo = new THREE.PlaneGeometry(200, 200);
            const createCarpetTexture = () => {
                const canvas = document.createElement("canvas");
                canvas.width = 512; canvas.height = 512;
                const ctx = canvas.getContext("2d");
                ctx.fillStyle = "#4a6b82"; // Blueish grey base
                ctx.fillRect(0, 0, 512, 512);
                ctx.fillStyle = "#d4af37"; // Gold/yellow spots
                for(let i=0; i<1000; i++) {
                    ctx.beginPath();
                    ctx.arc(Math.random()*512, Math.random()*512, Math.random()*4+1, 0, Math.PI*2);
                    ctx.fill();
                }
                ctx.fillStyle = "#2c404e"; 
                for(let i=0; i<1000; i++) {
                    ctx.beginPath();
                    ctx.arc(Math.random()*512, Math.random()*512, Math.random()*5+1, 0, Math.PI*2);
                    ctx.fill();
                }
                const tex = new THREE.CanvasTexture(canvas);
                tex.wrapS = THREE.RepeatWrapping; tex.wrapT = THREE.RepeatWrapping;
                tex.repeat.set(10, 10);
                return tex;
            };
            const floorMat = new THREE.MeshStandardMaterial({ map: createCarpetTexture(), roughness: 0.9 });
            const floor = new THREE.Mesh(floorGeo, floorMat);
            floor.rotation.x = -Math.PI / 2;
            floor.position.y = -22; 
            floor.receiveShadow = true;
            roomGroup.add(floor);

            // Walls
            const wallGeo = new THREE.PlaneGeometry(200, 100);
            const wallMat = new THREE.MeshStandardMaterial({ color: 0xfdf6e3, roughness: 1.0 });
            const backWall = new THREE.Mesh(wallGeo, wallMat);
            backWall.position.set(0, 20, -80);
            backWall.receiveShadow = true;
            roomGroup.add(backWall);

            const leftWall = new THREE.Mesh(wallGeo, wallMat);
            leftWall.rotation.y = Math.PI / 2;
            leftWall.position.set(-80, 20, 0);
            leftWall.receiveShadow = true;
            roomGroup.add(leftWall);

            const rightWall = new THREE.Mesh(wallGeo, wallMat);
            rightWall.rotation.y = -Math.PI / 2;
            rightWall.position.set(80, 20, 0);
            rightWall.receiveShadow = true;
            roomGroup.add(rightWall);

            // Marble Table Top
            const createMarbleTexture = () => {
                const canvas = document.createElement("canvas");
                canvas.width = 1024;
                canvas.height = 1024;
                const ctx = canvas.getContext("2d");
                ctx.fillStyle = "#e8e8e8";
                ctx.fillRect(0, 0, 1024, 1024);
                ctx.globalAlpha = 0.4;
                for(let i = 0; i < 40; i++) {
                    ctx.beginPath();
                    let x = Math.random() * 1024;
                    let y = 0;
                    ctx.moveTo(x, y);
                    ctx.strokeStyle = Math.random() > 0.5 ? "#555555" : "#888888";
                    ctx.lineWidth = Math.random() * 3 + 1;
                    while(y < 1024) {
                        x += (Math.random() - 0.5) * 100;
                        y += Math.random() * 100 + 20;
                        ctx.lineTo(x, y);
                    }
                    ctx.stroke();
                }
                ctx.globalAlpha = 1.0;
                const tex = new THREE.CanvasTexture(canvas);
                tex.wrapS = THREE.RepeatWrapping;
                tex.wrapT = THREE.RepeatWrapping;
                tex.repeat.set(2, 2);
                return tex;
            };
            const tableGeo = new THREE.CylinderGeometry(10, 10, 1, 64);
            const tableMat = new THREE.MeshStandardMaterial({ map: createMarbleTexture(), roughness: 0.1, metalness: 0.1 });
            const table = new THREE.Mesh(tableGeo, tableMat);
            table.position.y = -7.5;
            table.receiveShadow = true;
                        roomGroup.add(table);
            
            // Official Document
            
            const createDocTexture = () => {
                const canvas = document.createElement("canvas");
                canvas.width = 512;
                canvas.height = 712;
                const ctx = canvas.getContext("2d");
                
                // Paper background
                ctx.fillStyle = "#f8f5e6";
                ctx.fillRect(0, 0, 512, 712);
                
                // Border/Margins
                ctx.strokeStyle = "#444";
                ctx.lineWidth = 1;
                ctx.strokeRect(15, 15, 482, 682);
                
                // White House Seal (Top Center/Left)
                const drawSeal = (x, y, size) => {
                    ctx.save();
                    ctx.translate(x, y);
                    
                    // Circles
                    ctx.strokeStyle = "#003366";
                    ctx.lineWidth = 1.5;
                    ctx.beginPath(); ctx.arc(0, 0, size/2, 0, Math.PI * 2); ctx.stroke();
                    ctx.lineWidth = 0.5;
                    ctx.beginPath(); ctx.arc(0, 0, size/2 - 3, 0, Math.PI * 2); ctx.stroke();
                    
                    // Text
                    ctx.fillStyle = "#003366";
                    ctx.font = "bold 6px 'Times New Roman', serif";
                    ctx.textAlign = "center";
                    const txt = "THE WHITE HOUSE • WASHINGTON";
                    for (let i = 0; i < txt.length; i++) {
                        ctx.save();
                        ctx.rotate((i * 2.8 * Math.PI / txt.length) - (Math.PI * 1.4));
                        ctx.fillText(txt[i], 0, -(size/2 - 7));
                        ctx.restore();
                    }
                    
                    // Eagle icon (simplified)
                    ctx.beginPath();
                    ctx.moveTo(-10, 0); ctx.lineTo(10, 0);
                    ctx.moveTo(0, -10); ctx.lineTo(0, 10);
                    ctx.stroke();
                    ctx.font = "14px serif";
                    ctx.fillText("🦅", 0, 5);
                    
                    ctx.restore();
                };
                drawSeal(70, 70, 80);
                
                // Title
                ctx.fillStyle = "#000";
                ctx.font = "bold 32px 'Courier New', serif";
                ctx.textAlign = "center";
                ctx.fillText("ENEMY LIST", 256, 120);
                
                // Helper for hand-drawn redactions
                const drawHandRedaction = (rx, ry, rw, rh) => {
                    ctx.save();
                    ctx.fillStyle = "rgba(0,0,0,0.95)";
                    ctx.beginPath();
                    // Jittered polygon for rough edges
                    const jitter = () => (Math.random() - 0.5) * 4;
                    ctx.moveTo(rx + jitter(), ry + jitter());
                    ctx.lineTo(rx + rw + jitter(), ry + jitter());
                    ctx.lineTo(rx + rw + jitter(), ry + rh + jitter());
                    ctx.lineTo(rx + jitter(), ry + rh + jitter());
                    ctx.closePath();
                    ctx.fill();
                    
                    // Extra "marker" strokes for texture
                    ctx.strokeStyle = "black";
                    ctx.lineWidth = 2;
                    for(let j=0; j<3; j++) {
                        ctx.beginPath();
                        ctx.moveTo(rx + 5, ry + rh/2 + jitter());
                        ctx.lineTo(rx + rw - 5, ry + rh/2 + jitter());
                        ctx.stroke();
                    }
                    ctx.restore();
                };

                // UNREDACTED (with UN blacked out)
                ctx.font = "bold 24px 'Courier New', serif";
                ctx.fillText("UNREDACTED", 256, 160);
                drawHandRedaction(182, 148, 28, 14); // Thinner strike-through for the joke
                
                // List of points
                ctx.textAlign = "left";
                ctx.font = "18px 'Courier New', serif";
                ctx.fillStyle = "#000";
                const listStartY = 210;
                const bulletGap = 35;
                for (let i = 0; i < 10; i++) {
                    const y = listStartY + i * bulletGap;
                    ctx.fillText("• ", 60, y + 15);
                    
                    // Randomized redaction lengths
                    const widths = [180, 220, 160, 250, 190, 210, 170, 230, 200, 240];
                    drawHandRedaction(85, y, widths[i % widths.length], 18);
                }
                
                // Footer Contact Info
                const footerY = 600;
                ctx.font = "16px 'Courier New', serif";
                ctx.fillText("Contact ", 60, footerY);
                drawHandRedaction(145, footerY - 14, 110, 18); // {Blacked out}
                ctx.fillText(" " + " ".repeat(20), 265, footerY);
                
                // Authentic Cursive Signature (S. Allmer style)
                ctx.save();
                ctx.translate(-60, 0); // Move slightly to the left
                ctx.strokeStyle = "#0055ff";
                ctx.lineWidth = 1.8;
                ctx.lineJoin = "round";
                ctx.lineCap = "round";
                ctx.beginPath();
                
                // "S"
                ctx.moveTo(310, 660);
                ctx.bezierCurveTo(305, 630, 345, 610, 335, 650);
                ctx.bezierCurveTo(325, 690, 360, 675, 370, 660);
                
                // Cursive "A"
                ctx.moveTo(385, 665);
                ctx.bezierCurveTo(395, 625, 415, 625, 405, 665);
                ctx.moveTo(405, 650);
                
                // "llmer" wiggles
                ctx.lineTo(415, 660);
                ctx.bezierCurveTo(420, 630, 425, 630, 425, 660); // l
                ctx.bezierCurveTo(430, 630, 435, 630, 435, 660); // l
                ctx.bezierCurveTo(440, 650, 450, 650, 455, 665); // m
                ctx.bezierCurveTo(460, 665, 465, 655, 470, 660); // e
                ctx.bezierCurveTo(480, 660, 490, 665, 500, 660); // r
                
                // Flourish/Underline
                ctx.moveTo(320, 680);
                ctx.bezierCurveTo(380, 685, 450, 675, 510, 670);
                
                ctx.stroke();
                ctx.restore();
                
                const tex = new THREE.CanvasTexture(canvas);
                tex.anisotropy = 4;
                return tex;
            };

            // 2. Enemy List Document Stack
            const docGroup = new THREE.Group();
            const numPages = 5;
            const pageTex = createDocTexture();
            
            for(let i=0; i<numPages; i++) {
                // Use thin BoxGeometry instead of Plane for "thickness"
                const pageGeo = new THREE.BoxGeometry(3, 0.015, 4.2);
                // Top page has the ENEMY LIST texture, others are slightly aged paper
                const pageMat = (i === numPages - 1) 
                    ? new THREE.MeshStandardMaterial({ map: pageTex, roughness: 0.85 })
                    : new THREE.MeshStandardMaterial({ color: 0xf8f5e6, roughness: 0.9 });
                
                const page = new THREE.Mesh(pageGeo, pageMat);
                page.position.y = i * 0.02; // Stack them
                // Slight misalignment for realism
                page.rotation.y = (Math.random() - 0.5) * 0.04;
                page.position.x = (Math.random() - 0.5) * 0.05;
                page.position.z = (Math.random() - 0.5) * 0.05;
                
                page.castShadow = true;
                page.receiveShadow = true;
                docGroup.add(page);
            }

            docGroup.position.set(-2.5, -7.0, 0.5);
            docGroup.rotation.y = Math.PI / 8;
            roomGroup.add(docGroup);

            // 2. Table Legs (Dark wood)
            const woodMat = new THREE.MeshStandardMaterial({ color: 0x2b1508, roughness: 0.7 });
            const centerLegGeo = new THREE.CylinderGeometry(2, 2, 14, 16);
            const centerLeg = new THREE.Mesh(centerLegGeo, woodMat);
            centerLeg.position.y = -15; 
            centerLeg.castShadow = true;
            centerLeg.receiveShadow = true;
            roomGroup.add(centerLeg);

            // 4 branching legs
            for(let i=0; i<4; i++) {
                const branchGeo = new THREE.CylinderGeometry(0.8, 0.5, 12, 8);
                const branch = new THREE.Mesh(branchGeo, woodMat);
                branch.position.set(0, -18, 0);
                branch.rotation.z = Math.PI / 4;
                
                const pivot = new THREE.Group();
                pivot.position.y = -18;
                pivot.rotation.y = (Math.PI / 2) * i;
                branch.position.set(6, -2, 0);
                pivot.add(branch);
                roomGroup.add(pivot);
            }





            roomGroup.scale.set(6, 6, 6);
            roomGroup.position.y = 35;
            scene.add(roomGroup);
            
            
            const camera = new THREE.PerspectiveCamera(45, container.clientWidth / container.clientHeight, 0.1, 1000);
            camera.position.set(20, 15, 30);
            
            const renderer = new THREE.WebGLRenderer({ antialias: true });
            renderer.setSize(container.clientWidth, container.clientHeight);
            renderer.shadowMap.enabled = true;
            container.appendChild(renderer.domElement);
            
            const controls = new THREE.OrbitControls(camera, renderer.domElement);
            controls.enableDamping = true;

            // Lights
            scene.add(new THREE.AmbientLight(0xffffff, 0.5));
            const spotLight = new THREE.SpotLight(0xffffff, 1);
            spotLight.position.set(20, 40, 20);
            spotLight.castShadow = true;
            spotLight.shadow.mapSize.width = 2048;
            spotLight.shadow.mapSize.height = 2048;
            scene.add(spotLight);

            // Textures
            const texLoader = new THREE.TextureLoader();
            const frontTex = texLoader.load(drawFront());
            const backTex = texLoader.load(drawCardBack());
            const sideTex = texLoader.load(drawSide());
            const topTex = createSALogoTexture(RED);
            const sealTex = texLoader.load(drawSealSymbol());
            const creamMat = new THREE.MeshStandardMaterial({ color: CREAM, roughness: 0.5 });

            // Main Box Body
            const bodyGeo = new THREE.BoxGeometry(10, 14, 3.2);
            const bodyMats = [
                new THREE.MeshStandardMaterial({ map: sideTex, roughness: 0.6 }), // Right
                new THREE.MeshStandardMaterial({ map: sideTex, roughness: 0.6 }), // Left
                new THREE.MeshStandardMaterial({ color: RED, roughness: 0.6 }), // Top (Changed from CREAM to RED to hide seams)
                new THREE.MeshStandardMaterial({ color: BLUE, roughness: 0.6 }), // Bottom
                new THREE.MeshStandardMaterial({ map: frontTex, roughness: 0.6 }), // Front
                new THREE.MeshStandardMaterial({ map: backTex, roughness: 0.6 })  // Back
            ];
            const body = new THREE.Mesh(bodyGeo, bodyMats);
            body.castShadow = true;
            body.receiveShadow = true;
            scene.add(body);

            // Internal Cards
            const cardsGeo = new THREE.BoxGeometry(9.6, 13.6, 3.0);
            const cardsMat = new THREE.MeshStandardMaterial({ color: 0xfcfaf0, roughness: 0.9 });
            const cards = new THREE.Mesh(cardsGeo, cardsMat);
            cards.position.y = -0.1; // Slightly lower so they don't peek out
            scene.add(cards);

            // Lid / Flap
            const flapGroup = new THREE.Group();
            flapGroup.position.set(0, 7, 1.6); // Hinge at top front edge
            scene.add(flapGroup);

            const flapGeo = new THREE.BoxGeometry(10.05, 0.15, 3.25);
            const flapMats = [
                new THREE.MeshStandardMaterial({ color: RED, roughness: 0.6 }), // Right
                new THREE.MeshStandardMaterial({ color: RED, roughness: 0.6 }), // Left
                new THREE.MeshStandardMaterial({ map: topTex, roughness: 0.4 }), // Top
                new THREE.MeshStandardMaterial({ color: CREAM, roughness: 0.5 }), // Bottom
                new THREE.MeshStandardMaterial({ color: RED, roughness: 0.6 }), // Front
                new THREE.MeshStandardMaterial({ color: RED, roughness: 0.6 })  // Back
            ];
            const flap = new THREE.Mesh(flapGeo, flapMats);
            flap.position.set(0, 0.05, -1.625); // Extend backwards from front hinge
            flapGroup.add(flap);

            // Seal Sticker (connecting top and back)
            const sealGeo = new THREE.BufferGeometry();
            const sealVertices = new Float32Array([
                -0.6,  0.13, -2.66, // 0: top-left front
                 0.6,  0.13, -2.66, // 1: top-right front
                -0.6,  0.13, -3.26, // 2: fold left
                 0.6,  0.13, -3.26, // 3: fold right
                -0.6, -0.47, -3.26, // 4: bottom left
                 0.6, -0.47, -3.26  // 5: bottom right
            ]);
            const sealIndices = [
                0, 2, 1,   2, 3, 1, // Top face
                2, 4, 3,   4, 5, 3  // Back face
            ];
            const sealUvs = new Float32Array([
                0, 1,   1, 1,
                0, 0.5, 1, 0.5,
                0, 0,   1, 0
            ]);
            sealGeo.setAttribute('position', new THREE.BufferAttribute(sealVertices, 3));
            sealGeo.setIndex(sealIndices);
            sealGeo.setAttribute('uv', new THREE.BufferAttribute(sealUvs, 2));
            sealGeo.computeVertexNormals();

            const sealMat = new THREE.MeshStandardMaterial({ 
                map: sealTex, 
                transparent: true,
                roughness: 0.3,
                side: THREE.DoubleSide
            });
            const seal = new THREE.Mesh(sealGeo, sealMat);
            flapGroup.add(seal);


            // Scattered Cards
            const drawAuthenticCard = (val, symbolType, bgColor) => {
                const canvas = document.createElement("canvas");
                canvas.width = 1438;
                canvas.height = 2048;
                const ctx = canvas.getContext("2d");
                
                ctx.fillStyle = bgColor;
                ctx.fillRect(0, 0, 1438, 2048);
                
                ctx.strokeStyle = "white";
                ctx.lineWidth = 30;
                ctx.strokeRect(20, 20, 1398, 2008);
                
                ctx.fillStyle = "white";
                let displayVal = val;
                if (val === "10" || val === 10) {
                    displayVal = "C";
                    ctx.font = "normal 160px 'Optima Black', sans-serif";
                } else {
                    ctx.font = "bold 160px 'Inter', sans-serif";
                }
                ctx.textAlign = "center";
                ctx.fillText(displayVal, 130, 200);
                ctx.save();
                ctx.translate(1308, 1850);
                ctx.rotate(Math.PI);
                ctx.fillText(displayVal, 0, 0);
                ctx.restore();
                
                ctx.save();
                ctx.translate(719, 1024);
                ctx.scale(3.2, 3.2);
                ctx.translate(-50, -50);

                let pathData = "";
                let circles = [];

                if (symbolType === 'cross') {
                    pathData = "M 45 22 L 45 35 Q 45 45 35 45 L 22 45 L 22 55 L 35 55 Q 45 55 45 65 L 45 78 L 55 78 L 55 65 Q 55 55 65 55 L 78 55 L 78 45 L 65 45 Q 55 45 55 35 L 55 22 Z";
                    circles = [[50, 14, 12], [39, 23, 9], [61, 23, 9], [50, 86, 12], [39, 77, 9], [61, 77, 9], [14, 50, 12], [23, 39, 9], [23, 61, 9], [86, 50, 12], [77, 39, 9], [77, 61, 9]];
                } else if (symbolType === 'star') {
                    pathData = "M 50 12 L 61 31 L 83 31 L 72 50 L 83 69 L 61 69 L 50 88 L 39 69 L 17 69 L 28 50 L 17 31 L 39 31 Z";
                    circles = [[50, 12, 6], [83, 31, 6], [83, 69, 6], [50, 88, 6], [17, 69, 6], [17, 31, 6]];
                } else if (symbolType === 'heart') {
                    pathData = "M 50 18 C 60 8, 78 10, 78 25 C 78 40, 54 35, 54 50 C 54 65, 78 60, 78 75 C 78 90, 60 92, 50 82 C 40 92, 22 90, 22 75 C 22 60, 46 65, 46 50 C 46 35, 22 40, 22 25 C 22 10, 40 8, 50 18 Z";
                }

                const p = new Path2D(pathData);
                ctx.globalAlpha = 1.0;
                ctx.fill(p);
                ctx.strokeStyle = "white";
                ctx.lineWidth = 1.5;
                ctx.stroke(p);

                circles.forEach(([cx, cy, r]) => {
                    ctx.beginPath();
                    ctx.arc(cx, cy, r, 0, Math.PI * 2);
                    ctx.globalAlpha = 1.0;
                    ctx.fill();
                    ctx.strokeStyle = "white";
                    ctx.lineWidth = 1;
                    ctx.stroke();
                });

                ctx.restore();
                
                const tex = new THREE.CanvasTexture(canvas);
                if(typeof renderer !== 'undefined') tex.generateMipmaps = false; tex.minFilter = THREE.LinearFilter; tex.magFilter = THREE.LinearFilter; tex.anisotropy = 4;
                return tex;
            };
            
            const faceTex1 = drawAuthenticCard("3", "cross", "#1b3a8b");
            const faceTex2 = drawAuthenticCard("6", "star", "#1a1c23");
            const faceTex3 = drawAuthenticCard("10", "heart", "#8b1b1b"); // Handled as 'C' in drawing logic

            const singleCardGeo = new THREE.BoxGeometry(1.58, 2.25, 0.005);
            
            const getCardMats = (faceTex) => [
                new THREE.MeshStandardMaterial({color:0xfcfaf0}),
                new THREE.MeshStandardMaterial({color:0xfcfaf0}),
                new THREE.MeshStandardMaterial({color:0xfcfaf0}),
                new THREE.MeshStandardMaterial({color:0xfcfaf0}),
                new THREE.MeshStandardMaterial({map: faceTex, roughness: 0.5}),
                new THREE.MeshStandardMaterial({map: backTex, roughness: 0.5})
            ];
            
            const card1 = new THREE.Mesh(singleCardGeo, getCardMats(faceTex1));
            card1.rotation.x = -Math.PI / 2;
            card1.position.set(2.2, -6.98, -1.0);
            card1.rotation.z = -Math.PI / 10;
            card1.castShadow = true;
            card1.receiveShadow = true;
            roomGroup.add(card1);

            const card2 = new THREE.Mesh(singleCardGeo, getCardMats(faceTex2));
            card2.rotation.x = -Math.PI / 2;
            card2.position.set(3.4, -6.96, 0.4);
            card2.rotation.z = Math.PI / 15;
            card2.castShadow = true;
            card2.receiveShadow = true;
            roomGroup.add(card2);
            
            const card3 = new THREE.Mesh(singleCardGeo, getCardMats(faceTex3));
            card3.rotation.x = -Math.PI / 2;
            card3.position.set(2.2, -6.99, 1.2);
            card3.rotation.z = Math.PI / 8;
            card3.castShadow = true;
            card3.receiveShadow = true;
            roomGroup.add(card3);


            // Interaction state
            let boxOpened = false;
            
            const openBox = () => {
                if (boxOpened) return;
                boxOpened = true;
                
                // Hide prompt if it exists
                const prompt = document.getElementById('interaction-prompt');
                if (prompt) prompt.style.opacity = '0';

                // Box opening animation
                gsap.to(flapGroup.rotation, { x: Math.PI * 1.05, duration: 1.2, ease: "back.inOut(1.2)" });
                gsap.to(cards.position, { 
                    y: 2.5, 
                    duration: 1.2, 
                    delay: 0.3, 
                    ease: "power2.inOut",
                    onComplete: () => {
                        // Redirect directly to the game setup
                        window.location.href = '../../../index.html#frontier';
                    }
                });
            };
            
            // Interaction triggers
            window.addEventListener('keydown', (e) => {
                if (e.code === 'Space') {
                    e.preventDefault();
                    openBox();
                }
            });
            
            window.addEventListener('click', () => {
                openBox();
            });
            
            window.addEventListener('touchstart', (e) => {
                // Ensure interaction registers on mobile
                openBox();
            }, { passive: true });

            function animate() {
                requestAnimationFrame(animate);
                controls.update();
                renderer.render(scene, camera);
            }
            animate();

            window.addEventListener('resize', () => {
                camera.aspect = container.clientWidth / container.clientHeight;
                camera.updateProjectionMatrix();
                renderer.setSize(container.clientWidth, container.clientHeight);
            });
        }


        init();
        
        // Hide loading after a delay to ensure font/textures are ready
        window.addEventListener('load', () => {
            setTimeout(() => {
                const loader = document.getElementById('loading');
                if (loader) {
                    loader.style.opacity = '0';
                    setTimeout(() => { loader.style.display = 'none'; }, 500);
                }
            }, 1000);
        });
        
        // Handle Escape key to go back
        window.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                window.location.href = '../../../index.html#games';
            }
        });
